function HealthVitalsTab({ userId, COLORS, FONTS, S }) {
  const [vitals, setVitals] = useState([]);
  const [form, setForm] = useState({ systolic:"", diastolic:"", sugar:"", heartRate:"", date: new Date().toISOString().split("T")[0], time:"morning" });
